/**
 * Geolocation helpers for use in middleware and edge functions.
 *
 * Extracts geolocation data from common CDN/proxy headers
 * (Vercel, Cloudflare) and provides distance calculation utilities.
 */

export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

const COUNTRY_NAMES: Record<string, string> = {
  US: 'United States',
  GB: 'United Kingdom',
  DE: 'Germany',
  FR: 'France',
  JP: 'Japan',
  CN: 'China',
  IN: 'India',
  BR: 'Brazil',
  AU: 'Australia',
  CA: 'Canada',
}

/**
 * Extracts geolocation data from the given `Headers` object.
 *
 * Reads Vercel `x-vercel-ip-*` headers and falls back to the Cloudflare
 * `cf-ipcountry` header for the country code.
 */
export function geoFromHeaders(headers: Headers): Geo {
  const city = headers.get('x-vercel-ip-city') || undefined
  const region = headers.get('x-vercel-ip-country-region') || undefined
  const latitude = headers.get('x-vercel-ip-latitude') || undefined
  const longitude = headers.get('x-vercel-ip-longitude') || undefined
  const timezone = headers.get('x-vercel-ip-timezone') || undefined

  // Vercel header takes precedence, Cloudflare as fallback
  const countryCode =
    headers.get('x-vercel-ip-country') ||
    headers.get('cf-ipcountry') ||
    undefined

  const country = countryCode
    ? COUNTRY_NAMES[countryCode.toUpperCase()] || undefined
    : undefined

  return {
    city,
    country,
    countryCode,
    region,
    latitude,
    longitude,
    timezone,
  }
}

/**
 * Extracts geolocation data from a request-like object that has a
 * `headers` property.
 */
export function geo(req: { headers: Headers }): Geo {
  return geoFromHeaders(req.headers)
}

/**
 * Checks whether the given `Geo` object's `countryCode` is included in the
 * provided list of region codes. The comparison is case-insensitive.
 */
export function isInRegion(geoData: Geo, regions: string[]): boolean {
  if (!geoData.countryCode) {
    return false
  }
  const code = geoData.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

/**
 * Calculates the Haversine distance in kilometres between two geographic
 * points specified as latitude/longitude strings.
 */
export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const toRad = (deg: number): number => (deg * Math.PI) / 180

  const R = 6371 // Earth's radius in kilometres
  const dLat = toRad(parseFloat(lat2) - parseFloat(lat1))
  const dLon = toRad(parseFloat(lon2) - parseFloat(lon1))
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(parseFloat(lat1))) *
      Math.cos(toRad(parseFloat(lat2))) *
      Math.sin(dLon / 2) *
      Math.sin(dLon / 2)
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
  return R * c
}

