import { describe, it, expect } from '@jest/globals'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

describe('geo()', () => {
  it('extracts geolocation from Vercel headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'San Francisco',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })

    const result = geo({ headers })

    expect(result.city).toBe('San Francisco')
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
    expect(result.region).toBe('CA')
    expect(result.latitude).toBe('37.7749')
    expect(result.longitude).toBe('-122.4194')
    expect(result.timezone).toBe('America/Los_Angeles')
  })

  it('returns undefined fields when headers are missing', () => {
    const headers = new Headers()
    const result = geo({ headers })

    expect(result.city).toBeUndefined()
    expect(result.countryCode).toBeUndefined()
    expect(result.country).toBeUndefined()
    expect(result.region).toBeUndefined()
    expect(result.latitude).toBeUndefined()
    expect(result.longitude).toBeUndefined()
    expect(result.timezone).toBeUndefined()
  })
})

describe('geoFromHeaders()', () => {
  it('falls back to Cloudflare cf-ipcountry header', () => {
    const headers = new Headers({
      'cf-ipcountry': 'GB',
    })

    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('GB')
    expect(result.country).toBe('United Kingdom')
  })

  it('prefers Vercel header over Cloudflare header', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'DE',
      'cf-ipcountry': 'FR',
    })

    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('looks up country name from countryCode', () => {
    const cases: Array<[string, string]> = [
      ['US', 'United States'],
      ['GB', 'United Kingdom'],
      ['DE', 'Germany'],
      ['FR', 'France'],
      ['JP', 'Japan'],
      ['CN', 'China'],
      ['IN', 'India'],
      ['BR', 'Brazil'],
      ['AU', 'Australia'],
      ['CA', 'Canada'],
    ]

    for (const [code, name] of cases) {
      const headers = new Headers({ 'x-vercel-ip-country': code })
      const result = geoFromHeaders(headers)
      expect(result.country).toBe(name)
    }
  })

  it('returns undefined country for unknown countryCode', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'ZZ',
    })

    const result = geoFromHeaders(headers)

    expect(result.countryCode).toBe('ZZ')
    expect(result.country).toBeUndefined()
  })
})

describe('isInRegion()', () => {
  it('returns true when countryCode matches a region', () => {
    expect(isInRegion({ countryCode: 'US' }, ['US', 'CA', 'MX'])).toBe(true)
  })

  it('performs case-insensitive comparison', () => {
    expect(isInRegion({ countryCode: 'us' }, ['US', 'CA'])).toBe(true)
    expect(isInRegion({ countryCode: 'US' }, ['us', 'ca'])).toBe(true)
  })

  it('returns false when countryCode does not match', () => {
    expect(isInRegion({ countryCode: 'GB' }, ['US', 'CA', 'MX'])).toBe(false)
  })

  it('returns false when countryCode is undefined', () => {
    expect(isInRegion({}, ['US', 'CA'])).toBe(false)
  })
})

describe('geoDistance()', () => {
  it('calculates distance between New York and London (~5570 km)', () => {
    // New York: 40.7128° N, 74.0060° W
    // London: 51.5074° N, 0.1278° W
    const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(Math.abs(distance - 5570)).toBeLessThan(50)
  })

  it('returns 0 for the same point', () => {
    const distance = geoDistance('37.7749', '-122.4194', '37.7749', '-122.4194')
    expect(distance).toBe(0)
  })

  it('calculates distance between Tokyo and Sydney (~7826 km)', () => {
    // Tokyo: 35.6762° N, 139.6503° E
    // Sydney: -33.8688° S, 151.2093° E
    const distance = geoDistance('35.6762', '139.6503', '-33.8688', '151.2093')
    expect(Math.abs(distance - 7826)).toBeLessThan(50)
  })
})

